def filtrar_acima(valores, limite):
    saida = []
    for v in valores:
        if v > limite:
            saida.append(v)
    return saida

print(filtrar_acima([10, 80, 55, 20], 50))   # [80, 55]

def aplicar_reajuste(valores, taxa):
    novos = []
    for v in valores:
        novos.append(v * (1 + taxa))
    return novos

print(aplicar_reajuste([100.0, 200.0], 0.10))  # [110.0, 220.0]

def contar_criticos(valores, limite):
    total = 0
    for v in valores:
        if v >= limite:
            total += 1
    return total

print(contar_criticos([30, 70, 90, 40], 70))   # 2

def despesas_criticas(valores, teto):
    saida = []
    for v in valores:
        if v >= teto:
            saida.append(v)
    return saida

despesas = [450.0, 1200.0, 800.0, 90.0, 1600.0]
print(despesas_criticas(despesas, 800.0))   # [1200.0, 800.0, 1600.0]

def arredondar(valores):
    saida = []
    for v in valores:
        saida.append(round(v))
    return saida

print(arredondar([1.4, 2.7, 3.5]))   # [1, 3, 4]
